/**
 * Tool registry — spec §16.
 *
 * Single source of truth for the §16 floating tool palette.
 *
 *   - `TOOL_REGISTRY` lists every primary drawing tool with its spec'd
 *     hotkey, lucide icon name (resolved via `Icons[icon]`), and per-mode
 *     visibility.
 *   - `paletteForMode(mode)` returns the ordered tool buttons for a
 *     given workspace mode (Plan, 3D, Plan+3D, Section, etc.).
 *   - `isToolDisabled(tool, document)` lets the palette dim tools that
 *     can't activate (e.g. Floor before any walls exist).
 *
 * Per-tool grammar specs (location-line cycle, chain mode, sketch-vs-
 * pick, etc.) live in `tools/<tool>.ts` and are referenced from this
 * registry by the `kind` discriminator.
 */

import type { IconName } from '@bim-ai/ui';

export type ToolId =
  | 'select'
  | 'wall'
  | 'door'
  | 'window'
  | 'floor'
  | 'roof'
  | 'stair'
  | 'railing'
  | 'room'
  | 'dimension'
  | 'section'
  | 'tag';

export type WorkspaceMode = 'plan' | '3d' | 'plan-3d' | 'section' | 'sheet' | 'schedule' | 'agent';

export interface ToolDefinition {
  id: ToolId;
  label: string;
  icon: IconName;
  /** Hotkey label (the actual key handler is wired by WP-UI-D03). */
  hotkey: string;
  /** Workspace modes where this tool button shows. */
  modes: WorkspaceMode[];
  /** Optional helper text shown in the tooltip. */
  tooltip?: string;
}

export const TOOL_REGISTRY: Record<ToolId, ToolDefinition> = {
  select: {
    id: 'select',
    label: 'Select',
    icon: 'select',
    hotkey: 'V',
    modes: ['plan', '3d', 'plan-3d', 'section', 'sheet', 'schedule', 'agent'],
    tooltip: 'Pick or marquee-select elements',
  },
  wall: {
    id: 'wall',
    label: 'Wall',
    icon: 'wall',
    hotkey: 'W',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Draw a wall (chain mode; Tab cycles location-line)',
  },
  door: {
    id: 'door',
    label: 'Door',
    icon: 'door',
    hotkey: 'D',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Insert door on wall (Spacebar flips swing)',
  },
  window: {
    id: 'window',
    label: 'Window',
    icon: 'window',
    hotkey: 'Shift+W',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Insert window on wall',
  },
  floor: {
    id: 'floor',
    label: 'Floor',
    icon: 'floor',
    hotkey: 'F',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Pick walls or sketch a floor outline',
  },
  roof: {
    id: 'roof',
    label: 'Roof',
    icon: 'roof',
    hotkey: 'R',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Pick walls or sketch a roof outline',
  },
  stair: {
    id: 'stair',
    label: 'Stair',
    icon: 'stair',
    hotkey: 'S',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Two-click run; auto-computes risers',
  },
  railing: {
    id: 'railing',
    label: 'Railing',
    icon: 'railing',
    hotkey: 'Shift+R',
    modes: ['plan', 'plan-3d', '3d'],
    tooltip: 'Pick host (stair / slab edge) or sketch path',
  },
  room: {
    id: 'room',
    label: 'Room',
    icon: 'room',
    hotkey: 'M',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Drop room marker in centroid of bounded area',
  },
  dimension: {
    id: 'dimension',
    label: 'Dimension',
    icon: 'dimension',
    hotkey: 'Shift+D',
    modes: ['plan', 'plan-3d', 'section'],
    tooltip: 'Linear / Aligned / Angular / Radial / Diameter',
  },
  section: {
    id: 'section',
    label: 'Section',
    icon: 'section',
    hotkey: 'Shift+S',
    modes: ['plan', 'plan-3d', 'section'],
    tooltip: 'Two-click section line + depth direction',
  },
  tag: {
    id: 'tag',
    label: 'Tag',
    icon: 'tag',
    hotkey: 'T',
    modes: ['plan', 'plan-3d'],
    tooltip: 'Tag dropdown (Door / Window / Wall / Room / By category)',
  },
};

/** Ordered palette layout per spec §16.1: select | tools | tag-subdropdown. */
const PALETTE_ORDER: ToolId[] = [
  'select',
  'wall',
  'door',
  'window',
  'floor',
  'roof',
  'stair',
  'railing',
  'room',
  'dimension',
  'section',
  'tag',
];

export function paletteForMode(mode: WorkspaceMode): ToolDefinition[] {
  return PALETTE_ORDER.map((id) => TOOL_REGISTRY[id]).filter((t) => t.modes.includes(mode));
}

export interface ToolDisabledContext {
  hasAnyWall: boolean;
  hasAnyFloor: boolean;
  hasAnySelection: boolean;
}

/** Tool-level enablement — `floor` requires a wall, `railing` requires a
 * stair or floor, etc. Used by §16.2 to dim disabled buttons. */
export function isToolDisabled(
  toolId: ToolId,
  ctx: ToolDisabledContext,
): { disabled: boolean; reason?: string } {
  switch (toolId) {
    case 'floor':
      if (!ctx.hasAnyWall) return { disabled: true, reason: 'Draw a wall first' };
      return { disabled: false };
    case 'roof':
      if (!ctx.hasAnyWall) return { disabled: true, reason: 'Draw a wall first' };
      return { disabled: false };
    case 'railing':
      if (!ctx.hasAnyFloor && !ctx.hasAnyWall) {
        return { disabled: true, reason: 'Add a stair or slab first' };
      }
      return { disabled: false };
    case 'dimension':
      if (!ctx.hasAnyWall) return { disabled: true, reason: 'Nothing to dimension' };
      return { disabled: false };
    default:
      return { disabled: false };
  }
}

/**
 * Cheatsheet data — spec §19.
 *
 * Canonical keyboard-shortcut catalogue. Grouped by section so the
 * `?`-modal can render an organised list. Tests assert that every
 * spec'd action lives here.
 */

export interface CheatsheetEntry {
  action: string;
  keys: string;
}

export interface CheatsheetSection {
  id: string;
  label: string;
  entries: CheatsheetEntry[];
}

export const CHEATSHEET: CheatsheetSection[] = [
  {
    id: 'global',
    label: 'Global',
    entries: [
      { action: 'Command palette', keys: '⌘K / Ctrl+K' },
      { action: 'Show this cheatsheet', keys: '?' },
      { action: 'Cancel', keys: 'Escape' },
      { action: 'Confirm / Apply', keys: 'Enter' },
      { action: 'Save bundle', keys: '⌘S' },
      { action: 'Toggle theme', keys: '⌘⇧L' },
    ],
  },
  {
    id: 'modes',
    label: 'Workspace modes',
    entries: [
      { action: 'Plan', keys: '1' },
      { action: '3D', keys: '2' },
      { action: 'Plan + 3D', keys: '3' },
      { action: 'Section', keys: '4' },
      { action: 'Sheet', keys: '5' },
      { action: 'Schedule', keys: '6' },
      { action: 'Agent', keys: '7' },
    ],
  },
  {
    id: 'tools',
    label: 'Drawing tools',
    entries: [
      { action: 'Select', keys: 'V' },
      { action: 'Wall', keys: 'W' },
      { action: 'Door', keys: 'D' },
      { action: 'Window', keys: 'Shift+W' },
      { action: 'Floor', keys: 'F (plan canvas)' },
      { action: 'Roof', keys: 'R' },
      { action: 'Stair', keys: 'S' },
      { action: 'Railing', keys: 'Shift+R' },
      { action: 'Room marker', keys: 'M' },
      { action: 'Dimension', keys: 'Shift+D' },
      { action: 'Section', keys: 'Shift+S' },
      { action: 'Tag', keys: 'T' },
    ],
  },
  {
    id: 'nav3d',
    label: '3D navigation (orbit mode)',
    entries: [
      { action: 'Orbit', keys: 'LMB drag · Alt+LMB' },
      { action: 'Pan', keys: 'RMB drag · Shift+LMB · MMB drag' },
      { action: 'Zoom in / out', keys: 'Scroll wheel · Pinch' },
      { action: 'Zoom step', keys: '⌘= / ⌘-' },
      { action: 'Fit all to view', keys: 'F' },
      { action: 'Fit selection', keys: '⌘F / Ctrl+F' },
      { action: 'Reset view', keys: 'H · Home' },
      { action: 'Enter walk mode', keys: 'Click Walk button (bottom-left)' },
    ],
  },
  {
    id: 'walk',
    label: '3D navigation (walk mode)',
    entries: [
      { action: 'Move forward / back', keys: 'W / S · ↑ / ↓' },
      { action: 'Strafe left / right', keys: 'A / D · ← / →' },
      { action: 'Ascend / descend', keys: 'E / Q' },
      { action: 'Run', keys: 'Shift (hold)' },
      { action: 'Look around', keys: 'Mouse (pointer locked)' },
      { action: 'Jump to floor above', keys: 'PageUp' },
      { action: 'Jump to floor below', keys: 'PageDown' },
      { action: 'Exit walk mode', keys: 'Esc' },
    ],
  },
  {
    id: 'nav2d',
    label: '2D plan navigation',
    entries: [
      { action: 'Pan', keys: 'LMB drag (empty space) · RMB drag · Space+LMB · MMB' },
      { action: 'Zoom in / out', keys: 'Scroll wheel · Pinch' },
      { action: 'Zoom presets', keys: 'Click scale bar (bottom-left)' },
      { action: 'Fit to view', keys: 'Shift+F · scale bar → Fit to view' },
    ],
  },
  {
    id: 'history',
    label: 'History',
    entries: [
      { action: 'Undo', keys: '⌘Z' },
      { action: 'Redo', keys: '⇧⌘Z' },
    ],
  },
  {
    id: 'shell',
    label: 'Shell',
    entries: [
      { action: 'Toggle left rail', keys: '[' },
      { action: 'Toggle right rail', keys: ']' },
    ],
  },
];

/** Flat list of every action — useful for tests. */
export function flattenCheatsheet(): CheatsheetEntry[] {
  return CHEATSHEET.flatMap((s) => s.entries);
}

/** Filter entries that match `query` (case-insensitive substring on
 * action or keys). Empty query returns the original sections. */
export function filterCheatsheet(query: string): CheatsheetSection[] {
  const q = query.trim().toLowerCase();
  if (!q) return CHEATSHEET;
  const out: CheatsheetSection[] = [];
  for (const s of CHEATSHEET) {
    const entries = s.entries.filter(
      (e) => e.action.toLowerCase().includes(q) || e.keys.toLowerCase().includes(q),
    );
    if (entries.length) out.push({ ...s, entries });
  }
  return out;
}

/** True if a key event should open the cheatsheet — `?` (Shift+/). */
export function shouldOpenCheatsheet(event: { key: string; shiftKey?: boolean }): boolean {
  return event.key === '?' || (event.shiftKey === true && event.key === '/');
}

