290	          className={INPUT_CLS}
291	          defaultValue={el.name}
292	          key={`pv-name-${el.id}-${el.name}-${revision}`}
293	          onBlur={(e) => {
294	            const v = e.target.value.trim();
295	            if (!v || v === el.name) return;
296	            onPersistProperty('name', v);
297	          }}
298	        />
299	      </label>
300	
301	      <label className={LABEL_CLS}>
302	        Plan presentation
303	        <select
304	          className={INPUT_CLS}
305	          value={el.planPresentation ?? 'default'}
306	          onChange={(e) => onPersistProperty('planPresentation', e.target.value)}
307	        >
308	          <option value="default">Neutral</option>
309	          <option value="opening_focus">Opening focus</option>
310	          <option value="room_scheme">Room scheme</option>
311	        </select>
312	      </label>
313	
314	      <label className={LABEL_CLS}>
315	        Underlay level
316	        <select
317	          className={INPUT_CLS}
318	          value={el.underlayLevelId && levels.some((l) => l.id === el.underlayLevelId) ? el.underlayLevelId : ''}
319	          onChange={(e) => onPersistProperty('underlayLevelId', e.target.value)}
320	        >
