359	function UndoCluster({
360	  depth,
361	  onUndo,
362	  onRedo,
363	}: {
364	  depth: number;
365	  onUndo?: () => void;
366	  onRedo?: () => void;
367	}): JSX.Element {
368	  return (
369	    <div className="flex items-center gap-1">
