16	/**
17	 * Inspector / Right rail — spec §13.
18	 *
19	 * Anatomy:
20	 *   - Header: icon + element type + id (mono) + clear-selection button.
21	 *   - Tabs: Properties / Constraints / Identity (`role="tablist"`).
22	 *   - Body: render the active tab; consumers pass each tab's content
23	 *     through `tabs.{properties,constraints,identity}` props.
24	 *   - Sticky footer: Apply (Enter) / Reset (Esc) — only visible when the
25	 *     inspector reports `dirty=true`.
26	 *
27	 * `evaluateExpression` exposes the §13.3 numeric-field grammar
28	 * (`2400 + 200`, `1500 / 2` etc.) so inspector callers can wire it into
29	 * their numeric inputs uniformly. `<NumericField>` is a primitive that
30	 * uses the evaluator + an optional unit chip (mm / cm / m).
31	 *
32	 * Empty state: when `selection` is null, an instruction block renders the
33	 * tool-mode "quick actions" hint set instead of the tab UI.
34	 */
35	
36	export type InspectorTab = 'properties' | 'constraints' | 'identity' | 'graphics';
37	
38	export interface InspectorSelection {
39	  /** Lucide icon to show in the header next to the type. */
40	  icon?: LucideLikeIcon;
41	  /** Human-readable element type, e.g. "Wall · Generic 200 mm". */
42	  label: string;
43	  /** Element id (rendered in mono). */
44	  id: string;
45	}
46	
47	export interface InspectorProps {
48	  selection: InspectorSelection | null;
49	  tabs: {
50	    properties: ReactNode;
51	    constraints?: ReactNode;
52	    identity?: ReactNode;
53	    /** When provided, a "Graphics" tab appears after Identity. */
54	    graphics?: ReactNode;
55	  };
56	  /** Quick-action lines for the empty state — typically tool hints
57	   * sourced from the active mode. `onTrigger` makes them clickable; if
58	   * omitted, rows render as static hints with a key chip only. */
59	  emptyStateActions?: { hotkey: string; label: string; onTrigger?: () => void }[];
60	  /** When `true` Apply / Reset footer is shown. */
61	  dirty?: boolean;
62	  onApply?: () => void;
63	  onReset?: () => void;
64	  onClearSelection?: () => void;
65	  /** Initial active tab; uncontrolled. */
66	  defaultTab?: InspectorTab;
67	}
68	
69	export function Inspector({
70	  selection,
71	  tabs,
72	  emptyStateActions,
73	  dirty = false,
74	  onApply,
75	  onReset,
76	  onClearSelection,
77	  defaultTab = 'properties',
78	}: InspectorProps): JSX.Element {
79	  const [activeTab, setActiveTab] = useState<InspectorTab>(defaultTab);
80	  const tablistId = useId();
81	
82	  const hasGraphics = tabs.graphics !== undefined;
83	  const tabDefs = useMemo<{ id: InspectorTab; label: string }[]>(() => {
84	    const defs: { id: InspectorTab; label: string }[] = [
85	      { id: 'properties', label: 'Properties' },
86	      { id: 'constraints', label: 'Constraints' },
87	      { id: 'identity', label: 'Identity' },
88	    ];
89	    if (hasGraphics) defs.push({ id: 'graphics', label: 'Graphics' });
90	    return defs;
91	  }, [hasGraphics]);
92	
93	  useEffect(() => {
94	    if (activeTab === 'graphics' && !hasGraphics) setActiveTab('properties');
95	  }, [activeTab, hasGraphics]);
96	
97	  const handleTabKey = useCallback(
98	    (event: KeyboardEvent<HTMLDivElement>) => {
99	      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
100	      const idx = tabDefs.findIndex((t) => t.id === activeTab);
101	      if (idx < 0) return;
102	      const delta = event.key === 'ArrowRight' ? 1 : -1;
103	      const next = tabDefs[(idx + delta + tabDefs.length) % tabDefs.length];
104	      event.preventDefault();
105	      setActiveTab(next.id);
