138	            aria-label="Inspector tabs"
139	            onKeyDown={handleTabKey}
140	            className="flex border-b border-border px-3"
141	          >
142	            {tabDefs.map((t) => {
143	              const active = t.id === activeTab;
144	              return (
145	                <button
146	                  key={t.id}
147	                  type="button"
148	                  role="tab"
