153	                  data-active={active ? 'true' : 'false'}
154	                  className={[
155	                    'px-3 py-2 text-sm transition-colors',
156	                    active
157	                      ? 'border-b-2 border-accent text-foreground'
158	                      : 'border-b-2 border-transparent text-muted hover:text-foreground',
159	                  ].join(' ')}
160	                >
161	                  {t.label}
