  },
  {
    id: 'modes',
    label: 'Workspace modes',
    entries: [
      { action: 'Plan', keys: '1' },
      { action: '3D', keys: '2' },
      { action: 'Plan + 3D', keys: '3' },
      { action: 'Section', keys: '4' },
      { action: 'Sheet', keys: '5' },
      { action: 'Schedule', keys: '6' },
      { action: 'Agent', keys: '7' },
    ],
  },
  {
    id: 'tools',
