1	import { type JSX, type KeyboardEvent, useCallback, useEffect, useMemo, useState } from 'react';
2	import { useTranslation } from 'react-i18next';
3	import { Icons, ICON_SIZE } from '@bim-ai/ui';
4	import { getCheatsheetData, filterCheatsheet } from './cheatsheetData';
5	
6	/**
7	 * Cheatsheet modal — spec §19.
8	 *
9	 * Opens when the user presses `?` (or Shift + /) — open/close ownership
10	 * is the caller's; this component just renders the sheet when `open` is
11	 * true. `Escape` closes; section filtering is keyboard-accessible.
12	 */
13	
14	export interface CheatsheetModalProps {
15	  open: boolean;
16	  onClose: () => void;
17	}
18	
19	export function CheatsheetModal({ open, onClose }: CheatsheetModalProps): JSX.Element | null {
20	  const { t } = useTranslation();
21	  const [query, setQuery] = useState('');
22	  const allSections = useMemo(() => getCheatsheetData(t), [t]);
23	
24	  useEffect(() => {
25	    if (!open) setQuery('');
26	  }, [open]);
27	
28	  const handleBackdropKey = useCallback(
29	    (event: KeyboardEvent<HTMLDivElement>) => {
30	      if (event.key === 'Escape') {
31	        event.preventDefault();
32	        onClose();
33	      }
34	    },
35	    [onClose],
36	  );
37	
38	  if (!open) return null;
39	  const sections = filterCheatsheet(query, t);
40	
41	  return (
42	    <div
43	      role="dialog"
44	      aria-modal="true"
45	      aria-label={t('cheatsheet.modalAriaLabel')}
46	      data-testid="cheatsheet-modal"
47	      onKeyDown={handleBackdropKey}
48	      style={{
49	        position: 'fixed',
50	        inset: 0,
51	        zIndex: 70,
52	        display: 'flex',
53	        alignItems: 'center',
54	        justifyContent: 'center',
55	        background: 'rgba(8, 12, 20, 0.42)',
56	        backdropFilter: 'blur(2px)',
57	      }}
58	      onClick={(e) => {
59	        if (e.target === e.currentTarget) onClose();
60	      }}
61	    >
62	      <div
63	        className="flex max-h-[80vh] w-full max-w-3xl flex-col overflow-hidden rounded-xl border border-border bg-surface shadow-elev-3"
64	        style={{ minWidth: 480 }}
65	      >
66	        <div className="flex items-center gap-3 border-b border-border px-4 py-3">
67	          <Icons.commandPalette
68	            size={ICON_SIZE.toolPalette}
69	            aria-hidden="true"
70	            className="text-muted"
71	          />
72	          <h2 className="flex-1 text-md font-medium text-foreground">{t('cheatsheet.actions.showCheatsheet')}</h2>
73	          <button
74	            type="button"
75	            onClick={onClose}
76	            aria-label={t('cheatsheet.closeAriaLabel')}
77	            className="inline-flex h-7 w-7 items-center justify-center rounded-md text-muted hover:bg-surface-strong"
78	          >
79	            <Icons.close size={ICON_SIZE.chrome} aria-hidden="true" />
80	          </button>
81	        </div>
82	        <div className="border-b border-border px-4 py-2">
83	          <input
84	            type="search"
85	            placeholder={t('cheatsheet.filterPlaceholder')}
86	            aria-label={t('cheatsheet.filterAriaLabel')}
87	            value={query}
88	            onChange={(e) => setQuery(e.target.value)}
89	            autoFocus
90	            className="w-full rounded-md border border-border bg-background px-3 py-1.5 text-sm text-foreground outline-none placeholder:text-muted"
91	          />
92	        </div>
93	        <div className="flex-1 overflow-y-auto px-4 py-3">
94	          {sections.length === 0 ? (
95	            <p className="py-6 text-center text-sm text-muted">{t('cheatsheet.noMatches')}</p>
96	          ) : (
97	            sections.map((section) => (
98	              <div key={section.id} className="mb-4">
99	                <div
100	                  className="mb-2 text-xs uppercase text-muted"
101	                  style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
102	                >
103	                  {section.label}
104	                </div>
105	                <ul className="flex flex-col gap-1">
106	                  {section.entries.map((entry) => (
107	                    <li
108	                      key={`${section.id}:${entry.action}:${entry.keys}`}
109	                      className="flex items-center justify-between gap-4 rounded-md px-2 py-1.5 hover:bg-surface-strong"
110	                    >
111	                      <span className="text-sm text-foreground">{entry.action}</span>
112	                      <kbd className="rounded-sm border border-border bg-background px-2 py-0.5 font-mono text-xs text-muted">
113	                        {entry.keys}
114	                      </kbd>
115	                    </li>
116	                  ))}
117	                </ul>
118	              </div>
119	            ))
120	          )}
121	        </div>
122	        <div className="border-t border-border bg-surface-muted px-4 py-2 text-xs text-muted">
123	          {allSections.flatMap((s) => s.entries).length} shortcuts · Esc to close
124	        </div>
125	      </div>
126	    </div>
127	  );
128	}

