  safe: 'safe retry',
  blocked: 'blocked',
  requires_manual_edit: 'manual edit',
};

function ConflictSlot({
  queue,
  onClear,
}: {
  queue: CollaborationConflictQueueV1;
  onClear?: () => void;
}): JSX.Element {
  const [expanded, setExpanded] = useState(false);
