import { afterEach, describe, expect, it, vi } from 'vitest';
import { cleanup, fireEvent, render } from '@testing-library/react';
import { I18nextProvider } from 'react-i18next';
import { ToolPalette } from './ToolPalette';
import { paletteForMode } from './toolRegistry';
import i18n from '../i18n';

const tIdentity = (key: string) => key;

function renderWithI18n(ui: React.ReactElement) {
  return render(ui, {
    wrapper: ({ children }: { children: React.ReactNode }) => (
      <I18nextProvider i18n={i18n}>{children}</I18nextProvider>
    ),
  });
}

afterEach(() => {
  cleanup();
});

const ENABLED_CTX = { hasAnyWall: true, hasAnyFloor: true, hasAnySelection: false };

describe('paletteForMode — spec §16.1', () => {
  it('plan mode includes Wall/Door/Window/Floor/Roof/Stair/Room/Dimension/Section/Tag/Select', () => {
    const ids = paletteForMode('plan', tIdentity as never).map((t) => t.id);
    for (const required of [
      'select',
      'wall',
      'door',
      'window',
      'floor',
      'roof',
      'stair',
      'room',
      'dimension',
      'section',
      'tag',
    ]) {
      expect(ids).toContain(required);
    }
  });

  it('schedule mode only includes select', () => {
    const ids = paletteForMode('schedule', tIdentity as never).map((t) => t.id);
    expect(ids).toEqual(['select']);
  });
});

describe('<ToolPalette /> — spec §16', () => {
  it('renders all plan-mode tools as toolbar buttons', () => {
    const { getByLabelText } = renderWithI18n(
      <ToolPalette
        mode="plan"
        activeTool="select"
        onToolSelect={() => undefined}
        disabledContext={ENABLED_CTX}
      />,
    );
    expect(getByLabelText('Wall (W)')).toBeTruthy();
    expect(getByLabelText('Door (D)')).toBeTruthy();
    expect(getByLabelText('Section (Shift+S)')).toBeTruthy();
  });

  it('marks the active tool with aria-pressed and tabIndex 0', () => {
    const { getByLabelText, getAllByRole } = renderWithI18n(
      <ToolPalette
        mode="plan"
        activeTool="wall"
        onToolSelect={() => undefined}
        disabledContext={ENABLED_CTX}
      />,
    );
    const wall = getByLabelText('Wall (W)') as HTMLButtonElement;
    expect(wall.getAttribute('aria-pressed')).toBe('true');
    expect(wall.tabIndex).toBe(0);
    const inactive = getAllByRole('button').filter(
      (b) => b !== wall && !(b as HTMLButtonElement).disabled,
    );
    inactive.forEach((b) => {
      expect((b as HTMLButtonElement).tabIndex).toBe(-1);
    });
  });

  it('emits onToolSelect when a tool is clicked', () => {
    const onSelect = vi.fn();
    const { getByLabelText } = renderWithI18n(
      <ToolPalette
        mode="plan"
        activeTool="select"
        onToolSelect={onSelect}
        disabledContext={ENABLED_CTX}
      />,
    );
    fireEvent.click(getByLabelText('Door (D)'));
    expect(onSelect).toHaveBeenCalledWith('door');
  });

  it('cycles tools with ArrowRight / ArrowLeft', () => {
    const onSelect = vi.fn();
    const { getByRole } = renderWithI18n(
      <ToolPalette
        mode="plan"
        activeTool="select"
        onToolSelect={onSelect}
        disabledContext={ENABLED_CTX}
      />,
    );
    fireEvent.keyDown(getByRole('toolbar'), { key: 'ArrowRight' });
    expect(onSelect).toHaveBeenLastCalledWith('wall');
    fireEvent.keyDown(getByRole('toolbar'), { key: 'ArrowLeft' });
    expect(onSelect).toHaveBeenLastCalledWith('tag'); // wraps backwards from select
  });

  it('disables Floor when no walls exist and surfaces the reason', () => {
    const { getByLabelText } = renderWithI18n(
      <ToolPalette
        mode="plan"
        activeTool="select"
        onToolSelect={() => undefined}
        disabledContext={{ hasAnyWall: false, hasAnyFloor: false, hasAnySelection: false }}
      />,
    );
    const floor = getByLabelText('Floor (F)') as HTMLButtonElement;
    expect(floor.disabled).toBe(true);
    expect(floor.title).toMatch(/wall first/);
  });

  it('Tag button dispatches onTagSubmenu instead of onToolSelect', () => {
    const onSelect = vi.fn();
    const onTag = vi.fn();
    const { getByLabelText } = renderWithI18n(
      <ToolPalette
        mode="plan"
        activeTool="select"
        onToolSelect={onSelect}
        onTagSubmenu={onTag}
        disabledContext={ENABLED_CTX}
      />,
    );
    fireEvent.click(getByLabelText('Tag (T)'));
    expect(onTag).toHaveBeenCalled();
    expect(onSelect).not.toHaveBeenCalled();
  });
});

import { afterEach, describe, expect, it, vi } from 'vitest';
import { cleanup, fireEvent, render } from '@testing-library/react';
import { I18nextProvider } from 'react-i18next';
import { Inspector, NumericField, evaluateExpression, type InspectorSelection } from './Inspector';
import i18n from '../i18n';

function renderWithI18n(ui: React.ReactElement) {
  return render(ui, {
    wrapper: ({ children }: { children: React.ReactNode }) => (
      <I18nextProvider i18n={i18n}>{children}</I18nextProvider>
    ),
  });
}

afterEach(() => {
  cleanup();
});

const selection: InspectorSelection = {
  label: 'Wall · Generic 200 mm',
  id: 'seed-w-eg-south-main',
};

describe('Inspector — spec §13', () => {
  it('renders the empty state with quick actions when nothing is selected', () => {
    const { getByText } = renderWithI18n(
      <Inspector
        selection={null}
        tabs={{ properties: <div /> }}
        emptyStateActions={[
          { hotkey: 'W', label: 'Draw a wall' },
          { hotkey: 'D', label: 'Insert a door' },
        ]}
      />,
    );
    expect(getByText('No selection.')).toBeTruthy();
    expect(getByText('Draw a wall')).toBeTruthy();
    expect(getByText('Insert a door')).toBeTruthy();
  });

  it('renders header, three tabs, and Properties body when selection set', () => {
    const { getByText, getAllByRole } = renderWithI18n(
      <Inspector
        selection={selection}
        tabs={{
          properties: <div data-testid="props-body">props</div>,
          constraints: <div>constraints</div>,
          identity: <div>identity</div>,
        }}
      />,
    );
    expect(getByText('Wall · Generic 200 mm')).toBeTruthy();
    const tabs = getAllByRole('tab');
    expect(tabs.map((t) => t.textContent)).toEqual(['Properties', 'Constraints', 'Identity']);
    expect(getByText('props')).toBeTruthy();
  });

  it('switches body when tab is clicked', () => {
    const { getByText, queryByText } = renderWithI18n(
      <Inspector
        selection={selection}
        tabs={{
          properties: <div>props</div>,
          constraints: <div>constraints</div>,
          identity: <div>identity</div>,
        }}
      />,
    );
    expect(queryByText('constraints')).toBeNull();
    fireEvent.click(getByText('Constraints'));
    expect(getByText('constraints')).toBeTruthy();
  });

  it('cycles tabs with ArrowLeft / ArrowRight', () => {
    const { getByRole, getByText } = renderWithI18n(
      <Inspector
        selection={selection}
        tabs={{
          properties: <div>props</div>,
          constraints: <div>constraints</div>,
          identity: <div>identity</div>,
        }}
      />,
    );
    const tablist = getByRole('tablist');
    fireEvent.keyDown(tablist, { key: 'ArrowRight' });
    expect(getByText('constraints')).toBeTruthy();
    fireEvent.keyDown(tablist, { key: 'ArrowRight' });
    expect(getByText('identity')).toBeTruthy();
    fireEvent.keyDown(tablist, { key: 'ArrowLeft' });
    expect(getByText('constraints')).toBeTruthy();
  });

  it('shows Apply / Reset footer only when dirty', () => {
    const onApply = vi.fn();
    const onReset = vi.fn();
    const { queryByText, rerender, getByText } = renderWithI18n(
      <Inspector
        selection={selection}
        tabs={{ properties: <div>props</div> }}
        onApply={onApply}
        onReset={onReset}
      />,
    );
    expect(queryByText('Apply (⏎)')).toBeNull();
    rerender(
      <Inspector
        selection={selection}
        tabs={{ properties: <div>props</div> }}
        onApply={onApply}
        onReset={onReset}
        dirty
      />,
    );
    expect(getByText('Apply (⏎)')).toBeTruthy();
    fireEvent.click(getByText('Apply (⏎)'));
    expect(onApply).toHaveBeenCalled();
    fireEvent.click(getByText('Reset (Esc)'));
    expect(onReset).toHaveBeenCalled();
  });

  it('emits onClearSelection when the close button is clicked', () => {
    const onClearSelection = vi.fn();
    const { getByLabelText } = renderWithI18n(
      <Inspector
        selection={selection}
        tabs={{ properties: <div>props</div> }}
        onClearSelection={onClearSelection}
      />,
    );
    fireEvent.click(getByLabelText('Close'));
    expect(onClearSelection).toHaveBeenCalled();
  });
});

describe('evaluateExpression — §13.3 numeric grammar', () => {
  it('evaluates simple arithmetic', () => {
    expect(evaluateExpression('2400 + 200')).toBe(2600);
    expect(evaluateExpression('1500 / 2')).toBe(750);
    expect(evaluateExpression('(100 + 50) * 2')).toBe(300);
  });
  it('returns null for non-numeric input', () => {
    expect(evaluateExpression('alert(1)')).toBeNull();
    expect(evaluateExpression('drop database')).toBeNull();
    expect(evaluateExpression('')).toBeNull();
  });
});

describe('NumericField', () => {
  it('renders the value in the chosen unit', () => {
    const { getByLabelText } = renderWithI18n(
      <NumericField label="Width" valueMm={1500} onCommitMm={() => undefined} unit="m" />,
    );
    expect((getByLabelText('Width') as HTMLInputElement).value).toBe('1.500');
  });

  it('cycles units mm → cm → m → mm', () => {
    const { getByRole } = renderWithI18n(
      <NumericField label="Width" valueMm={1500} onCommitMm={() => undefined} />,
    );
    const chip = getByRole('button');
    expect(chip.textContent).toBe('mm');
    fireEvent.click(chip);
    expect(chip.textContent).toBe('cm');
    fireEvent.click(chip);
    expect(chip.textContent).toBe('m');
    fireEvent.click(chip);
    expect(chip.textContent).toBe('mm');
  });

  it('commits an expression on blur', () => {
    const onCommitMm = vi.fn();
    const { getByLabelText } = renderWithI18n(
      <NumericField label="Width" valueMm={1500} onCommitMm={onCommitMm} />,
    );
    const input = getByLabelText('Width') as HTMLInputElement;
    fireEvent.change(input, { target: { value: '2400 + 200' } });
    fireEvent.blur(input);
    expect(onCommitMm).toHaveBeenCalledWith(2600);
  });

  it('flags invalid expressions via aria-invalid', () => {
    const { getByLabelText } = renderWithI18n(
      <NumericField label="Width" valueMm={1500} onCommitMm={() => undefined} />,
    );
    const input = getByLabelText('Width') as HTMLInputElement;
    fireEvent.change(input, { target: { value: 'wat' } });
    fireEvent.blur(input);
    expect(input.getAttribute('aria-invalid')).toBe('true');
  });
});

import {
  type ChangeEvent,
  type CSSProperties,
  type FormEvent,
  type JSX,
  type KeyboardEvent,
  type ReactNode,
  useCallback,
  useEffect,
  useId,
  useMemo,
  useState,
} from 'react';
import { useTranslation } from 'react-i18next';
import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';

/**
 * Inspector / Right rail — spec §13.
 *
 * Anatomy:
 *   - Header: icon + element type + id (mono) + clear-selection button.
 *   - Tabs: Properties / Constraints / Identity (`role="tablist"`).
 *   - Body: render the active tab; consumers pass each tab's content
 *     through `tabs.{properties,constraints,identity}` props.
 *   - Sticky footer: Apply (Enter) / Reset (Esc) — only visible when the
 *     inspector reports `dirty=true`.
 *
 * `evaluateExpression` exposes the §13.3 numeric-field grammar
 * (`2400 + 200`, `1500 / 2` etc.) so inspector callers can wire it into
 * their numeric inputs uniformly. `<NumericField>` is a primitive that
 * uses the evaluator + an optional unit chip (mm / cm / m).
 *
 * Empty state: when `selection` is null, an instruction block renders the
 * tool-mode "quick actions" hint set instead of the tab UI.
 */

export type InspectorTab = 'properties' | 'constraints' | 'identity' | 'graphics';

export interface InspectorSelection {
  /** Lucide icon to show in the header next to the type. */
  icon?: LucideLikeIcon;
  /** Human-readable element type, e.g. "Wall · Generic 200 mm". */
  label: string;
  /** Element id (rendered in mono). */
  id: string;
}

export interface InspectorProps {
  selection: InspectorSelection | null;
  tabs: {
    properties: ReactNode;
    constraints?: ReactNode;
    identity?: ReactNode;
    /** When provided, a "Graphics" tab appears after Identity. */
    graphics?: ReactNode;
  };
  /** Quick-action lines for the empty state — typically tool hints
   * sourced from the active mode. `onTrigger` makes them clickable; if
   * omitted, rows render as static hints with a key chip only. */
  emptyStateActions?: { hotkey: string; label: string; onTrigger?: () => void }[];
  /** When `true` Apply / Reset footer is shown. */
  dirty?: boolean;
  onApply?: () => void;
  onReset?: () => void;
  onClearSelection?: () => void;
  /** Initial active tab; uncontrolled. */
  defaultTab?: InspectorTab;
}

export function Inspector({
  selection,
  tabs,
  emptyStateActions,
  dirty = false,
  onApply,
  onReset,
  onClearSelection,
  defaultTab = 'properties',
}: InspectorProps): JSX.Element {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<InspectorTab>(defaultTab);
  const tablistId = useId();

  const hasGraphics = tabs.graphics !== undefined;
  const tabDefs = useMemo<{ id: InspectorTab; label: string }[]>(() => {
    const defs: { id: InspectorTab; label: string }[] = [
      { id: 'properties', label: t('inspector.tabs.properties') },
      { id: 'constraints', label: t('inspector.tabs.constraints') },
      { id: 'identity', label: t('inspector.tabs.identity') },
    ];
    if (hasGraphics) defs.push({ id: 'graphics', label: t('inspector.tabs.graphics') });
    return defs;
  }, [hasGraphics, t]);

  useEffect(() => {
    if (activeTab === 'graphics' && !hasGraphics) setActiveTab('properties');
  }, [activeTab, hasGraphics]);

  const handleTabKey = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key !== 'ArrowRight' && event.key !== 'ArrowLeft') return;
      const idx = tabDefs.findIndex((t) => t.id === activeTab);
      if (idx < 0) return;
      const delta = event.key === 'ArrowRight' ? 1 : -1;
      const next = tabDefs[(idx + delta + tabDefs.length) % tabDefs.length];
      event.preventDefault();
      setActiveTab(next.id);
    },
    [activeTab, tabDefs],
  );

  const tabBody = useMemo(() => {
    if (!selection) return null;
    switch (activeTab) {
      case 'properties':
        return tabs.properties;
      case 'constraints':
        return tabs.constraints ?? <EmptyTab message={t('inspector.noConstraintsMeta')} />;
      case 'identity':
        return tabs.identity ?? <EmptyTab message={t('inspector.noIdentityMeta')} />;
      case 'graphics':
        return tabs.graphics ?? null;
      default:
        return null;
    }
  }, [activeTab, selection, tabs]);

  return (
    <div
      className="flex h-full flex-col overflow-hidden bg-surface"
      data-testid="inspector"
      data-dirty={dirty ? 'true' : 'false'}
    >
      {selection ? (
        <>
          <InspectorHeader selection={selection} onClearSelection={onClearSelection} />
          <div
            role="tablist"
            id={tablistId}
            aria-label={t('inspector.tabs.ariaLabel')}
            onKeyDown={handleTabKey}
            className="flex border-b border-border px-3"
          >
            {tabDefs.map((t) => {
              const active = t.id === activeTab;
              return (
                <button
                  key={t.id}
                  type="button"
                  role="tab"
                  aria-selected={active}
                  aria-controls={`${tablistId}-panel-${t.id}`}
                  tabIndex={active ? 0 : -1}
                  onClick={() => setActiveTab(t.id)}
                  data-active={active ? 'true' : 'false'}
                  className={[
                    'px-3 py-2 text-sm transition-colors',
                    active
                      ? 'border-b-2 border-accent text-foreground'
                      : 'border-b-2 border-transparent text-muted hover:text-foreground',
                  ].join(' ')}
                >
                  {t.label}
                </button>
              );
            })}
          </div>
          <div
            role="tabpanel"
            id={`${tablistId}-panel-${activeTab}`}
            aria-labelledby={tablistId}
            className="flex-1 overflow-y-auto px-3 py-3"
          >
            {tabBody}
          </div>
          {dirty ? <InspectorFooter onApply={onApply} onReset={onReset} /> : null}
        </>
      ) : (
        <InspectorEmpty actions={emptyStateActions ?? []} />
      )}
    </div>
  );
}

function InspectorHeader({
  selection,
  onClearSelection,
}: {
  selection: InspectorSelection;
  onClearSelection?: () => void;
}): JSX.Element {
  const Icon = selection.icon;
  return (
    <div className="flex items-start gap-3 border-b border-border px-3 py-3">
      <div className="flex h-9 w-9 items-center justify-center rounded-md bg-surface-strong">
        {Icon ? <Icon size={ICON_SIZE.toolPalette} aria-hidden="true" /> : null}
      </div>
      <div className="flex flex-1 flex-col">
        <div className="text-sm font-medium text-foreground">{selection.label}</div>
        <div className="font-mono text-xs text-muted">id · {selection.id}</div>
      </div>
      <button
        type="button"
        onClick={onClearSelection}
        aria-label={IconLabels.close}
        className="inline-flex h-7 w-7 items-center justify-center rounded-md text-muted hover:bg-surface-strong"
      >
        <Icons.close size={ICON_SIZE.chrome} aria-hidden="true" />
      </button>
    </div>
  );
}

function InspectorFooter({
  onApply,
  onReset,
}: {
  onApply?: () => void;
  onReset?: () => void;
}): JSX.Element {
  const { t } = useTranslation();
  const handleKey = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key === 'Enter') {
        event.preventDefault();
        onApply?.();
      } else if (event.key === 'Escape') {
        event.preventDefault();
        onReset?.();
      }
    },
    [onApply, onReset],
  );
  return (
    <div
      onKeyDown={handleKey}
      className="sticky bottom-0 flex items-center justify-end gap-2 border-t border-border bg-surface px-3 py-2"
    >
      <button
        type="button"
        onClick={onReset}
        className="rounded-md px-2 py-1 text-sm text-muted hover:bg-surface-strong"
      >
        {t('inspector.footer.reset')}
      </button>
      <button
        type="button"
        onClick={onApply}
        className="rounded-md bg-accent px-3 py-1 text-sm text-accent-foreground hover:opacity-90"
      >
        {t('inspector.footer.apply')}
      </button>
    </div>
  );
}

function InspectorEmpty({
  actions,
}: {
  actions: { hotkey: string; label: string; onTrigger?: () => void }[];
}): JSX.Element {
  const { t } = useTranslation();
  return (
    <div className="flex flex-1 flex-col gap-3 px-3 py-6 text-sm">
      <p className="text-foreground">{t('inspector.empty.noSelection')}</p>
      <p className="text-xs text-muted">
        {t('inspector.empty.hint')}
      </p>
      {actions.length ? (
        <div className="rounded-md border border-border bg-surface-strong p-3">
          <div
            className="mb-2 text-xs uppercase text-muted"
            style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
          >
            {t('inspector.empty.quickActions')}
          </div>
          <ul className="flex flex-col gap-1">
            {actions.map((a) => {
              const inner = (
                <>
                  <span>{a.label}</span>
                  <kbd className="rounded-sm bg-background px-1.5 py-0.5 font-mono text-[11px] text-muted">
                    {a.hotkey}
                  </kbd>
                </>
              );
              if (a.onTrigger) {
                return (
                  <li key={`${a.hotkey}:${a.label}`}>
                    <button
                      type="button"
                      onClick={a.onTrigger}
                      data-testid={`inspector-quick-action-${a.hotkey.toLowerCase()}`}
                      className="flex w-full items-center justify-between rounded px-1.5 py-1 text-left text-xs text-foreground hover:bg-background"
                    >
                      {inner}
                    </button>
                  </li>
                );
              }
              return (
                <li
                  key={`${a.hotkey}:${a.label}`}
                  className="flex items-center justify-between text-xs text-foreground"
                >
                  {inner}
                </li>
