47	/** Resolve a CSS color token to an rgb() string that Three.js can parse.
48	 * CSS Color Level 4 hsl() uses spaces (e.g. "hsl(0 0% 100%)") which
49	 * Three.js does not support — routing through a DOM element forces the
50	 * browser to resolve it to "rgb(r, g, b)". */
51	function readColorToken(name: string, fallback: string): string {
52	  if (typeof document === 'undefined') return fallback;
53	  try {
54	    const el = document.createElement('div');
55	    el.style.display = 'none';
56	    el.style.color = `var(${name}, ${fallback})`;
57	    document.body.appendChild(el);
58	    const resolved = getComputedStyle(el).color;
59	    document.body.removeChild(el);
60	    return resolved || fallback;
61	  } catch {
