66	function sunPositionFromAzEl(azimuthDeg: number, elevationDeg: number, radiusM = 80): THREE.Vector3 {
67	  const az = THREE.MathUtils.degToRad(azimuthDeg);
68	  const el = THREE.MathUtils.degToRad(elevationDeg);
69	  return new THREE.Vector3(
70	    radiusM * Math.cos(el) * Math.sin(az),
