85	  const color = readToken('--color-foreground', '#1a1a1a');
86	  const edges = new THREE.EdgesGeometry(mesh.geometry, thresholdAngleDeg);
87	  const mat = new THREE.LineBasicMaterial({ color, linewidth: 1 });
