96	type WallElem = Extract<Element, { kind: 'wall' }>;
97	
98	/** Footprints use world XZ with z ← plan yMm */
99	
100	function xzBoundsMm(poly: Array<{ xMm: number; yMm: number }>): {
101	  minX: number;
102	  maxX: number;
103	  minZ: number;
104	  maxZ: number;
105	  cx: number;
106	  cz: number;
107	  spanX: number;
108	  spanZ: number;
109	} {
110	  let minX = Number.POSITIVE_INFINITY;
111	  let maxX = Number.NEGATIVE_INFINITY;
112	  let minZ = Number.POSITIVE_INFINITY;
113	  let maxZ = Number.NEGATIVE_INFINITY;
114	  for (const p of poly) {
115	    minX = Math.min(minX, p.xMm);
116	
117	    maxX = Math.max(maxX, p.xMm);
118	
119	    minZ = Math.min(minZ, p.yMm);
120	
121	    maxZ = Math.max(maxZ, p.yMm);
122	  }
123	
124	  const spanX = Math.max(maxX - minX, 1);
125	
126	  const spanZ = Math.max(maxZ - minZ, 1);
127	
128	  return {
129	    minX,
130	
131	    maxX,
132	
133	    minZ,
134	
135	    maxZ,
136	
137	    cx: (minX + maxX) / 2,
138	
139	    cz: (minZ + maxZ) / 2,
140	
141	    spanX,
142	
143	    spanZ,
144	  };
145	}
146	
147	function elevationMForLevel(levelId: string, elementsById: Record<string, Element>): number {
148	  const lvl = elementsById[levelId];
149	  if (!lvl || lvl.kind !== 'level') return 0;
150	  return lvl.elevationMm / 1000;
151	}
152	
153	function hostedXZ(
154	  hosted: Extract<Element, { kind: 'door' } | { kind: 'window' }>,
155	  wall: WallElem,
156	): { px: number; pz: number } {
157	  const sx = wall.start.xMm / 1000;
158	  const sz = wall.start.yMm / 1000;
159	  const dx = wall.end.xMm / 1000 - sx;
160	  const dz = wall.end.yMm / 1000 - sz;
161	  const len = Math.max(1e-6, Math.hypot(dx, dz));
162	  const ux = dx / len;
163	  const uz = dz / len;
164	  return {
165	    px: sx + ux * hosted.alongT * len,
166	    pz: sz + uz * hosted.alongT * len,
167	  };
168	}
169	
170	function wallYaw(wall: WallElem) {
171	  const sx = wall.start.xMm / 1000;
172	  const sz = wall.start.yMm / 1000;
173	  const ex = wall.end.xMm / 1000;
174	  const ez = wall.end.yMm / 1000;
175	  return Math.atan2(ez - sz, ex - sx);
176	}
