178	function makeFloorSlabMesh(
179	  floor: Extract<Element, { kind: 'floor' }>,
180	  elementsById: Record<string, Element>,
181	  paint: ViewportPaintBundle | null,
182	): THREE.Mesh {
183	  const elev = elevationMForLevel(floor.levelId, elementsById);
184	  const th = THREE.MathUtils.clamp(floor.thicknessMm / 1000, 0.05, 1.8);
185	  const boundary = floor.boundaryMm ?? [];
186	
187	  // Build shape in shape-XY (plan X→shape X, plan Y negated→shape Y).
188	  // After ExtrudeGeometry + rotateX(-π/2): shape X→world X, extrude depth→world Y, −shapeY→world Z.
189	  const shape = new THREE.Shape(
190	    boundary.length >= 3
191	      ? boundary.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))
192	      : [
193	          new THREE.Vector2(0, 0),
194	          new THREE.Vector2(6, 0),
195	          new THREE.Vector2(6, -6),
196	          new THREE.Vector2(0, -6),
197	        ],
