199	
200	  // Punch holes for any slab openings hosted by this floor.
201	  for (const el of Object.values(elementsById)) {
202	    if (el.kind !== 'slab_opening' || el.hostFloorId !== floor.id) continue;
203	    const hPts = el.boundaryMm ?? [];
204	    if (hPts.length < 3) continue;
205	    shape.holes.push(
206	      new THREE.Path(hPts.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))),
