230	function makeRoofMassMesh(
231	  roof: Extract<Element, { kind: 'roof' }>,
232	  elementsById: Record<string, Element>,
233	  paint: ViewportPaintBundle | null,
234	): THREE.Mesh {
235	  const b = xzBoundsMm(roof.footprintMm ?? []);
236	
237	  const ov = THREE.MathUtils.clamp((roof.overhangMm ?? 0) / 1000, 0, 5);
238	
239	  const refElev = elevationMForLevel(roof.referenceLevelId, elementsById);
240	  // Eave plate = top of the tallest wall at the reference level.
241	  // Without this, the box proxy sits inside the upper-storey walls and is invisible.
242	  const wallsAtRefLevel = Object.values(elementsById).filter(
243	    (e): e is WallElem => e.kind === 'wall' && (e as WallElem).levelId === roof.referenceLevelId,
244	  );
245	  const wallTopM =
246	    wallsAtRefLevel.length > 0
247	      ? Math.max(...wallsAtRefLevel.map((w) => (w.heightMm ?? 0) / 1000))
248	      : 0;
249	  const eaveY = refElev + wallTopM;
250	
251	  const slopeRad = (THREE.MathUtils.clamp(Number(roof.slopeDeg ?? 25), 5, 70) * Math.PI) / 180;
252	  const spanXm = b.spanX / 1000;
253	  const spanZm = b.spanZ / 1000;
254	  const halfSpan = Math.min(spanXm, spanZm) / 2;
255	  const ridgeY = eaveY + halfSpan * Math.tan(slopeRad);
256	
257	  const ox0 = b.minX / 1000 - ov;
258	  const ox1 = b.maxX / 1000 + ov;
259	  const oz0 = b.minZ / 1000 - ov;
260	  const oz1 = b.maxZ / 1000 + ov;
261	
262	  // Triangulated gable mesh — ridge runs along the longer plan axis.
263	  let positions: number[];
264	  if (spanXm >= spanZm) {
265	    // Ridge east-west (along X); slopes drop to south (oz0) and north (oz1).
266	    const rz = (oz0 + oz1) / 2;
267	    positions = [
268	      // South slope
269	      ox0, eaveY, oz0,  ox1, eaveY, oz0,  ox0, ridgeY, rz,
270	      ox1, eaveY, oz0,  ox1, ridgeY, rz,  ox0, ridgeY, rz,
271	      // North slope
272	      ox0, ridgeY, rz,  ox1, ridgeY, rz,  ox0, eaveY, oz1,
273	      ox1, ridgeY, rz,  ox1, eaveY, oz1,  ox0, eaveY, oz1,
274	      // West gable
275	      ox0, eaveY, oz0,  ox0, ridgeY, rz,  ox0, eaveY, oz1,
276	      // East gable
277	      ox1, eaveY, oz0,  ox1, eaveY, oz1,  ox1, ridgeY, rz,
278	    ];
279	  } else {
280	    // Ridge north-south (along Z); slopes drop to west (ox0) and east (ox1).
281	    const rx = (ox0 + ox1) / 2;
282	    positions = [
283	      // West slope
284	      ox0, eaveY, oz0,  ox0, eaveY, oz1,  rx, ridgeY, oz0,
285	      ox0, eaveY, oz1,  rx, ridgeY, oz1,  rx, ridgeY, oz0,
286	      // East slope
287	      rx, ridgeY, oz0,  rx, ridgeY, oz1,  ox1, eaveY, oz0,
288	      rx, ridgeY, oz1,  ox1, eaveY, oz1,  ox1, eaveY, oz0,
289	      // South gable
290	      ox0, eaveY, oz0,  rx, ridgeY, oz0,  ox1, eaveY, oz0,
291	      // North gable
292	      ox0, eaveY, oz1,  ox1, eaveY, oz1,  rx, ridgeY, oz1,
293	    ];
294	  }
295	
296	  const geom = new THREE.BufferGeometry();
297	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
298	  geom.computeVertexNormals();
299	
300	  const mesh = new THREE.Mesh(
301	    geom,
302	    new THREE.MeshStandardMaterial({
303	      color: categoryColorOr(paint, 'roof'),
304	      transparent: true,
305	      opacity: 0.94,
306	      roughness: paint?.categories.roof.roughness ?? 0.74,
307	      metalness: 0.04,
308	      side: THREE.DoubleSide,
309	    }),
310	  );
311	  mesh.userData.bimPickId = roof.id;
312	  addEdges(mesh);
