316	function makeStairVolumeMesh(
317	  stair: Extract<Element, { kind: 'stair' }>,
318	  elementsById: Record<string, Element>,
319	  paint: ViewportPaintBundle | null,
320	  selectedId?: string,
321	): THREE.Group {
322	  const group = new THREE.Group();
323	
324	  const sx = stair.runStartMm.xMm / 1000;
325	  const sz = stair.runStartMm.yMm / 1000;
326	  const ex = stair.runEndMm.xMm / 1000;
327	  const ez = stair.runEndMm.yMm / 1000;
328	  const dx = ex - sx;
329	  const dz = ez - sz;
330	  const runLen = Math.max(1e-3, Math.hypot(dx, dz));
331	  const stairWidth = THREE.MathUtils.clamp(stair.widthMm / 1000, 0.3, 4);
332	
333	  const baseLevelElev = elevationMForLevel(stair.baseLevelId, elementsById);
334	  const topLevelElev = elevationMForLevel(stair.topLevelId, elementsById);
335	  const totalRise = Math.max(Math.abs(topLevelElev - baseLevelElev), 0.1);
336	
337	  const riserCount = Math.max(
338	    Math.round((totalRise * 1000) / (stair.riserMm > 0 ? stair.riserMm : 175)),
339	    2,
340	  );
341	  const riserH = totalRise / riserCount;
342	  const treadDepth = runLen / riserCount;
343	  const treadThick = 0.040;
344	  const angle = Math.atan2(dz, dx);
345	
346	  const stairColor =
347	    stair.id === selectedId
348	      ? (paint?.selection.selectedColor ?? '#fcd34d')
349	      : categoryColorOr(paint, 'stair');
350	  const mat = new THREE.MeshStandardMaterial({ color: stairColor });
351	
352	  const treadGeom = new THREE.BoxGeometry(treadDepth, treadThick, stairWidth);
353	  for (let i = 0; i < riserCount; i++) {
354	    const treadMesh = new THREE.Mesh(treadGeom, mat);
355	    const cx = sx + ((i + 0.5) / riserCount) * dx;
356	    const cz = sz + ((i + 0.5) / riserCount) * dz;
357	    // top surface of tread i sits at baseLevelElev + (i+1)*riserH
358	    const cy = baseLevelElev + (i + 1) * riserH - treadThick / 2;
359	    treadMesh.position.set(cx, cy, cz);
360	    treadMesh.rotation.y = angle;
361	    treadMesh.castShadow = true;
362	    treadMesh.receiveShadow = true;
363	    treadMesh.userData.bimPickId = stair.id;
364	    addEdges(treadMesh);
365	    group.add(treadMesh);
366	  }
367	
368	  // Side stringer plates offset laterally by ±stairWidth/2 along local Z
369	  // Local Z world direction for rotation.y = angle: (sin angle, 0, cos angle) = (dz/runLen, 0, dx/runLen)
370	  const stringerGeom = new THREE.BoxGeometry(runLen, totalRise, 0.025);
371	  const midCx = (sx + ex) / 2;
372	  const midCz = (sz + ez) / 2;
373	  const midCy = baseLevelElev + totalRise / 2;
374	  const perpX = dz / runLen;
375	  const perpZ = dx / runLen;
376	
377	  for (const side of [-1, 1] as const) {
378	    const stringer = new THREE.Mesh(stringerGeom, mat);
379	    stringer.position.set(
380	      midCx + perpX * side * (stairWidth / 2),
381	      midCy,
382	      midCz + perpZ * side * (stairWidth / 2),
383	    );
384	    stringer.rotation.y = angle;
385	    stringer.castShadow = true;
386	    stringer.receiveShadow = true;
387	    stringer.userData.bimPickId = stair.id;
388	    addEdges(stringer);
389	    group.add(stringer);
390	  }
391	
392	  group.userData.bimPickId = stair.id;
393	  return group;
394	}
