396	function makeWallMesh(
397	  wall: WallElem,
398	  elevM: number,
399	  paint: ViewportPaintBundle | null,
400	  selectedId?: string,
401	): THREE.Mesh {
402	  const sx = wall.start.xMm / 1000;
403	  const sz = wall.start.yMm / 1000;
404	  const ex = wall.end.xMm / 1000;
405	  const ez = wall.end.yMm / 1000;
406	  const dx = ex - sx;
407	  const dz = ez - sz;
408	  const len = Math.max(0.001, Math.hypot(dx, dz));
409	  const height = THREE.MathUtils.clamp(wall.heightMm / 1000, 0.25, 40);
410	  const thick = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2);
411	  const mesh = new THREE.Mesh(
412	    new THREE.BoxGeometry(len, height, thick),
413	    new THREE.MeshStandardMaterial({
414	      color:
415	        wall.id === selectedId
416	          ? (paint?.selection.selectedColor ?? '#fb923c')
417	          : categoryColorOr(paint, 'wall'),
418	      roughness: paint?.categories.wall.roughness ?? 0.85,
419	    }),
420	  );
421	  mesh.position.set(sx + dx / 2, elevM + height / 2, sz + dz / 2);
422	  mesh.rotation.y = Math.atan2(dz, dx);
423	  mesh.userData.bimPickId = wall.id;
424	  addEdges(mesh);
425	  return mesh;
426	}
