428	function makeDoorMesh(
429	  door: Extract<Element, { kind: 'door' }>,
430	  wall: WallElem,
431	  elevM: number,
432	  paint: ViewportPaintBundle | null,
433	  sid?: string,
434	) {
435	  const { px, pz } = hostedXZ(door, wall);
436	  const leafWidth  = THREE.MathUtils.clamp(door.widthMm / 1000, 0.35, 4);
437	  const leafHeight = THREE.MathUtils.clamp((wall.heightMm / 1000) * 0.86, 0.6, 2.5);
438	  const panelThick = 0.045;
439	  const depth      = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.08, 0.5);
440	  const frameSect  = 0.07;
441	
442	  const doorColor = door.id === sid
443	    ? (paint?.selection.selectedColor ?? '#fde047')
444	    : categoryColorOr(paint, 'door');
445	
446	  const frameMat = new THREE.MeshStandardMaterial({ color: doorColor });
447	  const panelMat = new THREE.MeshStandardMaterial({ color: doorColor, roughness: 0.75 });
448	
449	  function member(w: number, h: number, d: number, x: number, y: number, mat: THREE.MeshStandardMaterial): THREE.Mesh {
450	    const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), mat);
451	    m.position.set(x, y, 0);
452	    m.castShadow = m.receiveShadow = true;
453	    addEdges(m);
454	    return m;
455	  }
456	
457	  const frameGroup = new THREE.Group();
458	  // head spans full opening width including jambs
459	  frameGroup.add(member(leafWidth + 2 * frameSect, frameSect, depth, 0, leafHeight + frameSect / 2, frameMat));
460	  // jamb-L
461	  frameGroup.add(member(frameSect, leafHeight, depth, -(leafWidth / 2 + frameSect / 2), leafHeight / 2, frameMat));
462	  // jamb-R
463	  frameGroup.add(member(frameSect, leafHeight, depth,  (leafWidth / 2 + frameSect / 2), leafHeight / 2, frameMat));
464	
465	  // panel leaf
466	  const panelMesh = member(leafWidth, leafHeight, panelThick, 0, leafHeight / 2, panelMat);
467	
468	  // threshold sits at floor level (centre of 0.02 m height = 0.01 m above elevM)
469	  const threshMesh = member(leafWidth, 0.02, depth, 0, 0.01, frameMat);
470	
471	  const group = new THREE.Group();
472	  group.add(frameGroup, panelMesh, threshMesh);
473	  group.position.set(px, elevM, pz);
474	  group.rotation.y = wallYaw(wall);
475	  group.userData.bimPickId = door.id;
476	  return group;
477	}
