479	function makeWindowMesh(
480	  win: Extract<Element, { kind: 'window' }>,
481	  wall: WallElem,
482	  elevM: number,
483	  paint: ViewportPaintBundle | null,
484	  sid?: string,
485	) {
486	  const { px, pz } = hostedXZ(win, wall);
487	  const sill = THREE.MathUtils.clamp(win.sillHeightMm / 1000, 0.06, wall.heightMm / 1000 - 0.08);
488	  const outerW = THREE.MathUtils.clamp(win.widthMm / 1000, 0.14, 4);
489	  const outerH = THREE.MathUtils.clamp(
490	    win.heightMm / 1000,
491	    0.05,
492	    wall.heightMm / 1000 - sill - 0.06,
493	  );
494	  const frameSect = 0.06;
495	  const depth = THREE.MathUtils.clamp(wall.thicknessMm / 1000 + 0.02, 0.06, 0.5);
496	  const glazingW = Math.max(outerW - 2 * frameSect, 0.01);
497	  const glazingH = Math.max(outerH - 2 * frameSect, 0.01);
498	
499	  const frameColor =
500	    win.id === sid
501	      ? (paint?.selection.selectedColor ?? '#ddd6fe')
502	      : categoryColorOr(paint, 'window');
503	  const frameMat = new THREE.MeshStandardMaterial({ color: frameColor });
504	
505	  const group = new THREE.Group();
506	  group.userData.bimPickId = win.id;
507	
508	  const frameGroup = new THREE.Group();
509	
510	  const head = new THREE.Mesh(new THREE.BoxGeometry(outerW, frameSect, depth), frameMat);
511	  head.position.set(0, outerH / 2 - frameSect / 2, 0);
512	  head.castShadow = head.receiveShadow = true;
513	  head.userData.bimPickId = win.id;
514	  addEdges(head);
515	  frameGroup.add(head);
516	
517	  const sillMesh = new THREE.Mesh(new THREE.BoxGeometry(outerW, frameSect, depth), frameMat);
518	  sillMesh.position.set(0, -(outerH / 2 - frameSect / 2), 0);
519	  sillMesh.castShadow = sillMesh.receiveShadow = true;
520	  sillMesh.userData.bimPickId = win.id;
521	  addEdges(sillMesh);
522	  frameGroup.add(sillMesh);
523	
524	  const jambL = new THREE.Mesh(new THREE.BoxGeometry(frameSect, outerH, depth), frameMat);
525	  jambL.position.set(-(outerW / 2 - frameSect / 2), 0, 0);
526	  jambL.castShadow = jambL.receiveShadow = true;
527	  jambL.userData.bimPickId = win.id;
528	  addEdges(jambL);
529	  frameGroup.add(jambL);
530	
531	  const jambR = new THREE.Mesh(new THREE.BoxGeometry(frameSect, outerH, depth), frameMat);
532	  jambR.position.set(outerW / 2 - frameSect / 2, 0, 0);
533	  jambR.castShadow = jambR.receiveShadow = true;
534	  jambR.userData.bimPickId = win.id;
535	  addEdges(jambR);
536	  frameGroup.add(jambR);
537	
538	  group.add(frameGroup);
539	
540	  const glazingMat = new THREE.MeshStandardMaterial({
541	    color: readToken('--cat-glazing', '#c8d8ea'),
542	    roughness: 0.05,
543	    metalness: 0.0,
544	    opacity: 0.35,
545	    transparent: true,
546	    side: THREE.DoubleSide,
547	  });
548	  const glazing = new THREE.Mesh(new THREE.BoxGeometry(glazingW, glazingH, 0.006), glazingMat);
549	  glazing.castShadow = false;
550	  glazing.userData.bimPickId = win.id;
551	  group.add(glazing);
552	
553	  if (outerW > 1.2) {
554	    const mullion = new THREE.Mesh(
555	      new THREE.BoxGeometry(frameSect, glazingH, 0.012),
556	      frameMat,
557	    );
558	    mullion.castShadow = mullion.receiveShadow = true;
559	    mullion.userData.bimPickId = win.id;
560	    addEdges(mullion);
561	    group.add(mullion);
562	  }
563	
564	  group.position.set(px, elevM + sill + outerH / 2, pz);
565	  group.rotation.y = wallYaw(wall);
566	  return group;
567	}
