586	function makeRailingMesh(
587	  railing: Extract<Element, { kind: 'railing' }>,
588	  elementsById: Record<string, Element>,
589	  paint: ViewportPaintBundle | null,
590	): THREE.Group {
591	  const group = new THREE.Group();
592	  group.userData.bimPickId = railing.id;
593	
594	  const guardH = THREE.MathUtils.clamp((railing.guardHeightMm ?? 1050) / 1000, 0.5, 2.2);
595	  const pts = railing.pathMm ?? [];
596	  if (pts.length < 2) return group;
597	
598	  const stair = railing.hostedStairId ? elementsById[railing.hostedStairId] : null;
599	  const baseElev =
600	    stair?.kind === 'stair' ? elevationMForLevel(stair.baseLevelId, elementsById) : 0;
601	  const topElev =
602	    stair?.kind === 'stair' ? elevationMForLevel(stair.topLevelId, elementsById) : baseElev;
603	
604	  let totalPlanLen = 0;
605	  for (let i = 1; i < pts.length; i++) {
606	    totalPlanLen += Math.hypot(
607	      (pts[i]!.xMm - pts[i - 1]!.xMm) / 1000,
608	      (pts[i]!.yMm - pts[i - 1]!.yMm) / 1000,
609	    );
610	  }
611	
612	  const mat = new THREE.MeshStandardMaterial({
613	    color: categoryColorOr(paint, 'railing'),
614	    roughness: 0.35,
615	    metalness: 0.65,
616	  });
617	
618	  // Pre-compute cumulative parametric t at each vertex for slope interpolation
619	  const vertexT: number[] = [0];
620	  let cumForT = 0;
621	  for (let i = 1; i < pts.length; i++) {
622	    cumForT += Math.hypot(
623	      (pts[i]!.xMm - pts[i - 1]!.xMm) / 1000,
624	      (pts[i]!.yMm - pts[i - 1]!.yMm) / 1000,
625	    );
626	    vertexT.push(totalPlanLen > 0 ? cumForT / totalPlanLen : 1);
627	  }
628	
629	  // Square posts at each path vertex
630	  const postSect = 0.05;
631	  const postGeom = new THREE.BoxGeometry(postSect, guardH, postSect);
632	  for (let i = 0; i < pts.length; i++) {
633	    const t = vertexT[i]!;
634	    const floorY = baseElev + t * (topElev - baseElev);
635	    const post = new THREE.Mesh(postGeom, mat);
636	    post.position.set(pts[i]!.xMm / 1000, floorY + guardH / 2, pts[i]!.yMm / 1000);
637	    post.castShadow = post.receiveShadow = true;
638	    post.userData.bimPickId = railing.id;
639	    addEdges(post);
640	    group.add(post);
641	  }
642	
643	  // Rail cap segments + balusters between posts
644	  const capSect = 0.045;
645	  const balW = 0.012;
646	  const balSpacing = 0.115;
647	  const balGeom = new THREE.BoxGeometry(balW, guardH, balW);
648	
649	  let cumLen = 0;
650	  for (let i = 0; i < pts.length - 1; i++) {
651	    const a = pts[i]!;
652	    const b = pts[i + 1]!;
653	    const ax = a.xMm / 1000,
654	      az = a.yMm / 1000;
655	    const bx = b.xMm / 1000,
656	      bz = b.yMm / 1000;
657	    const planSeg = Math.max(0.001, Math.hypot(bx - ax, bz - az));
658	    const tA = totalPlanLen > 0 ? cumLen / totalPlanLen : 0;
659	    cumLen += planSeg;
660	    const tB = totalPlanLen > 0 ? cumLen / totalPlanLen : 1;
661	    const floorA = baseElev + tA * (topElev - baseElev);
662	    const floorB = baseElev + tB * (topElev - baseElev);
663	    const elevA = floorA + guardH;
664	    const elevB = floorB + guardH;
665	    const riseY = elevB - elevA;
666	
667	    // Rail cap segment
668	    const railLen = Math.sqrt(planSeg * planSeg + riseY * riseY);
669	    const rail = new THREE.Mesh(new THREE.BoxGeometry(railLen, capSect, capSect), mat);
670	    rail.position.set((ax + bx) / 2, (elevA + elevB) / 2, (az + bz) / 2);
671	    const dir = new THREE.Vector3(bx - ax, riseY, bz - az).normalize();
672	    rail.quaternion.setFromUnitVectors(new THREE.Vector3(1, 0, 0), dir);
673	    rail.castShadow = rail.receiveShadow = true;
674	    rail.userData.bimPickId = railing.id;
675	    addEdges(rail);
676	    group.add(rail);
677	
678	    // Evenly spaced balusters between the two posts
679	    const balCount = Math.max(0, Math.floor(planSeg / balSpacing));
680	    for (let j = 0; j < balCount; j++) {
681	      const tLocal = (j + 0.5) / balCount;
682	      const bxj = ax + tLocal * (bx - ax);
683	      const bzj = az + tLocal * (bz - az);
684	      const floorYj = floorA + tLocal * (floorB - floorA);
685	      const bal = new THREE.Mesh(balGeom, mat);
686	      bal.position.set(bxj, floorYj + guardH / 2, bzj);
687	      bal.castShadow = bal.receiveShadow = true;
688	      bal.userData.bimPickId = railing.id;
689	      addEdges(bal);
690	      group.add(bal);
691	    }
692	  }
693	
694	  return group;
695	}
