712	          new THREE.Vector2(20, -20),
713	          new THREE.Vector2(20, 20),
714	          new THREE.Vector2(-20, 20),
715	        ],
716	  );
717	
718	  const geom = new THREE.ExtrudeGeometry(shape, { depth: padTh, bevelEnabled: false });
719	  geom.rotateX(-Math.PI / 2);
720	
721	  const mesh = new THREE.Mesh(
