778	function aabbWireframeVertices(
779	  min: { x: number; y: number; z: number },
780	  max: { x: number; y: number; z: number },
781	): THREE.Vector3[] {
782	  const v = (x: number, y: number, z: number): THREE.Vector3 => new THREE.Vector3(x, y, z);
783	  const c000 = v(min.x, min.y, min.z);
784	  const c100 = v(max.x, min.y, min.z);
785	  const c010 = v(min.x, max.y, min.z);
786	  const c110 = v(max.x, max.y, min.z);
787	  const c001 = v(min.x, min.y, max.z);
788	  const c101 = v(max.x, min.y, max.z);
789	  const c011 = v(min.x, max.y, max.z);
790	  const c111 = v(max.x, max.y, max.z);
791	  // 12 edges as vertex pairs.
792	  return [
793	    c000,
794	    c100,
795	    c100,
796	    c110,
797	    c110,
798	    c010,
799	    c010,
800	    c000,
801	    c001,
802	    c101,
803	    c101,
804	    c111,
805	    c111,
806	    c011,
807	    c011,
808	    c001,
809	    c000,
810	    c001,
811	    c100,
812	    c101,
813	    c110,
814	    c111,
815	    c010,
816	    c011,
817	  ];
818	}
