820	function applyClippingPlanesToMeshes(root: THREE.Object3D, planes: THREE.Plane[]) {
821	  if (!planes.length) return;
822	  root.traverse((node) => {
823	    const mesh = node as THREE.Mesh;
824	    if (mesh.isMesh && mesh.material instanceof THREE.MeshStandardMaterial) {
825	      const m = mesh.material.clone();
826	      m.clippingPlanes = planes.slice();
827	      mesh.material = m;
828	    }
829	  });
830	}
