      {tabs.length === 0 ? (
        <div className="px-2 pb-1.5 text-xs text-muted">No views open</div>
      ) : null}
      {tabs.map((tab, idx) => {
        const Icon = TAB_KIND_ICON[tab.kind] ?? Icons.floor!;
        const isActive = tab.id === activeId;
        const isDragOver = dragOverIdx === idx && dragSrc !== null && dragSrc !== idx;
