              e.dataTransfer.effectAllowed = 'move';
              try {
                e.dataTransfer.setData('text/plain', String(idx));
              } catch {
                /* some browsers throw on setData inside synthetic events */
              }
            }}
            onDragOver={(e) => {
              if (!onReorder || dragSrc === null) return;
              e.preventDefault();
              e.dataTransfer.dropEffect = 'move';
              if (dragOverIdx !== idx) setDragOverIdx(idx);
            }}
            onDragLeave={() => {
              if (dragOverIdx === idx) setDragOverIdx(null);
            }}
            onDrop={(e) => {
              if (!onReorder || dragSrc === null) return;
              e.preventDefault();
              if (dragSrc !== idx) onReorder(dragSrc, idx);
              setDragSrc(null);
              setDragOverIdx(null);
            }}
            onDragEnd={() => {
              setDragSrc(null);
              setDragOverIdx(null);
            }}
            className={[
              'group flex items-center gap-1.5 rounded-t-md border border-b-0 px-3 py-1.5 text-xs font-medium transition-colors',
              isActive
                ? 'border-border bg-background text-foreground shadow-sm'
                : 'border-transparent text-muted hover:bg-background/60 hover:text-foreground',
              isDragOver ? 'ring-2 ring-accent ring-offset-0' : '',
            ].join(' ')}
            style={
              isActive
                ? { boxShadow: 'inset 0 -2px 0 0 var(--color-accent), 0 -1px 3px 0 rgba(0,0,0,0.04)' }
                : undefined
            }
          >
            <button
              type="button"
              onClick={() => onActivate(tab.id)}
              aria-label={`${TAB_KIND_LABEL[tab.kind]}: ${tab.label}`}
              className="flex items-center gap-1.5 rounded"
              title={`${TAB_KIND_LABEL[tab.kind]} · ${tab.label}`}
              data-testid={`tab-activate-${tab.id}`}
            >
              <Icon
                size={13}
                aria-hidden="true"
                className={isActive ? 'text-accent' : 'text-muted'}
              />
              <span className="whitespace-nowrap">{truncated}</span>
            </button>
            <button
              type="button"
              onClick={(e) => {
                e.stopPropagation();
                onClose(tab.id);
              }}
              aria-label={t('workspace.closeTab', { label: tab.label })}
              data-testid={`tab-close-${tab.id}`}
              className={[
                'rounded p-0.5 hover:bg-surface-strong',
                isActive ? 'opacity-50 hover:opacity-100' : 'opacity-0 group-hover:opacity-50 group-hover:hover:opacity-100',
              ].join(' ')}
            >
              <Icons.close size={11} aria-hidden="true" />
            </button>
          </div>
        );
      })}
      <div className="relative ml-1" ref={popoverRef}>
        <button
          type="button"
          onClick={() => setPopoverOpen((v) => !v)}
          aria-label={t('workspace.openNewView')}
          data-testid="tab-add-button"
          className="flex h-6 w-6 items-center justify-center rounded text-muted hover:bg-surface-strong hover:text-foreground"
          style={{ fontSize: 16, lineHeight: 1 }}
        >
          +
        </button>
        {popoverOpen ? (
          <div
            role="menu"
            data-testid="tab-add-popover"
            className="absolute left-0 top-full z-30 mt-1 flex min-w-[180px] flex-col rounded-md border border-border bg-surface shadow-elev-2"
          >
            {ADDABLE_KINDS.map((kind) => {
              const Icon = TAB_KIND_ICON[kind];
              return (
                <button
                  key={kind}
                  type="button"
                  role="menuitem"
                  onClick={() => {
                    setPopoverOpen(false);
                    onAdd?.(kind);
                  }}
                  className="flex items-center gap-2 px-3 py-1.5 text-left text-xs text-foreground hover:bg-surface-strong"
                  data-testid={`tab-add-${kind}`}
                >
                  <Icon size={ICON_SIZE.chrome} aria-hidden="true" />
                  <span>+ {TAB_KIND_LABEL[kind]}</span>
                </button>
              );
            })}
          </div>
        ) : null}
      </div>
    </div>
  );
}

